  ('diplomatic-0248a032-moex-00470', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-111-7f4830a9', 'sub-diplomatic-0248a032-03', NULL, 'single_choice', '清廷新設「總理各國事務衙門」以主持外交業務，是在那個條約之後？', '["中美望廈條約", "英法北京條約", "中英虎門條約", "中法黃浦條約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:57+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00471', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-111-7f4830a9', 'sub-diplomatic-0248a032-03', NULL, 'single_choice', '南京條約的補充版本「五口通商章程」及「虎門條約」的相關規定，那一項並不侵犯中國主權？', '["協定關稅", "領事裁判權", "兵船停泊權", "特赦罪犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:57+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00472', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-111-7f4830a9', 'sub-diplomatic-0248a032-03', NULL, 'single_choice', '民國建立後，關於袁世凱政府的外交活動，下列敘述何者正確？', '["美國公使朱爾典（JohnNewellJordan）擔任北京公使團團長，和袁世凱交好，發揮了相當的影 響力", "袁世凱「善後大借款」，得到了包括美國在內的五國銀行團支持", "民國3年（1914年）第一次世界大戰爆發，袁世凱主導了中國對德國宣戰", "民國4年（1915年）中日「二十一條」談判，其中包含了「漢冶萍」鋼鐵廠的經營權問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:57+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00473', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-111-7f4830a9', 'sub-diplomatic-0248a032-03', NULL, 'single_choice', '關於列強從清末至民國初年在山東的活動，下列敘述何者錯誤？', '["光緒23年（1897年）德國出兵占據膠州灣，開啟了接下來的「瓜分危機」", "民國3年（1914年），第一次世界大戰爆發，日本藉口「英日同盟」而對德宣戰，並因此取得 山東青島的控制權", "民國4年（1915年）中日「二十一條」談判，袁世凱承認日本繼承德國在山東的一切權利，換 文中表示對於日本提議「欣然同意」，成為後來巴黎和會上，日本取得山東的憑據", "民國8年（1919年）5月4日，巴黎和會有關山東問題的決議，傳回國內，北京學生遊行抗議， 要求當局不得簽約，懲處相關官員，成為「五四運動」的導火線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:57+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00474', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-111-7f4830a9', 'sub-diplomatic-0248a032-03', NULL, 'single_choice', '中日關係於民國20年（1931年）「九一八」事變後不斷惡化，下列敘述何者錯誤？', '["民國21年（1932年），日本激進軍人闖入東京首相官邸，槍殺了傾向和平解決中日問題的首相 田中義一，史稱「五一五」事件", "民國22年（1933年），日軍進攻熱河，與中國軍隊爆發「長城戰役」，最後以中日《塘沽協定》 作結", "民國24年（1935年），日本製造「華北自治運動」，提出「廣田三原則」的外相是廣田弘毅", "民國26年（1937年），日軍進攻北平附近蘆溝橋，史稱「七七事變」，衝突旋即擴大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:57+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00475', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-111-7f4830a9', 'sub-diplomatic-0248a032-03', NULL, 'single_choice', '誰創造了「軟實力」這個用語？', '["奈伊（JosephNye）", "米爾斯海默（JohnMearsheimer）", "季辛吉（HenryKissinger）", "溫特（AlexanderWendt）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:57+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL)
